import{_ as a,o as r,c as t,a2 as s}from"./chunks/framework.BWuWLRhz.js";const o="/assets/Clash-Verge-01.B2Jw9Qph.png",l="/assets/Clash-Verge-02.BEZjw40U.png",n="/assets/Clash-Verge-03.DipCuOie.png",i="/assets/Clash-Verge-04.Bs-KsiJt.png",c="/assets/Clash-Verge-05.BnKFhiWp.png",h="/assets/Clash-Verge-08.CPJOCYux.png",g="/assets/Clash-Verge-07.D3UBDbp8.png",p="/assets/Clash-Verge-06.YMcn1D_r.png",x=JSON.parse('{"title":"Clash Verge Rev for macOS","description":"macOS 首选客户端 Clash Verge Rev 图文配置教程，含安全设置与五步连接。","frontmatter":{"description":"macOS 首选客户端 Clash Verge Rev 图文配置教程，含安全设置与五步连接。"},"headers":[],"relativePath":"clients/macos/clash-verge.md","filePath":"clients/macos/clash-verge.md","lastUpdated":1783294793000}'),d={name:"clients/macos/clash-verge.md"};function m(u,e,_,b,f,v){return r(),t("div",null,[...e[0]||(e[0]=[s('<h1 id="clash-verge-rev-for-macos" tabindex="-1">Clash Verge Rev for macOS <a class="header-anchor" href="#clash-verge-rev-for-macos" aria-label="Permalink to &quot;Clash Verge Rev for macOS&quot;">​</a></h1><blockquote><p><strong>macOS 推荐客户端</strong> | 图形化清晰，规则分流完善，适合长期使用</p></blockquote><p><a href="https://github.com/clash-verge-rev/clash-verge-rev" target="_blank" rel="noreferrer">Clash Verge Rev</a> 为 macOS 提供现代化代理体验，支持 Apple Silicon 与 Intel 双架构，与 Windows 版配置习惯一致。</p><h2 id="系统要求" tabindex="-1">系统要求 <a class="header-anchor" href="#系统要求" aria-label="Permalink to &quot;系统要求&quot;">​</a></h2><ul><li>最低版本：macOS 11 及以上</li><li>推荐版本：macOS 13 及以上</li><li>处理器：Intel x64 / Apple Silicon</li><li>内存：4GB（推荐 8GB 及以上）</li></ul><h2 id="下载与安装" tabindex="-1">下载与安装 <a class="header-anchor" href="#下载与安装" aria-label="Permalink to &quot;下载与安装&quot;">​</a></h2><ul><li>Apple Silicon（直链）：<a href="https://github.com/clash-verge-rev/clash-verge-rev/releases/download/v2.4.7/Clash.Verge_2.4.7_aarch64.dmg" target="_blank" rel="noreferrer">下载 dmg</a></li><li>Intel x64（直链）：<a href="https://github.com/clash-verge-rev/clash-verge-rev/releases/download/v2.4.7/Clash.Verge_2.4.7_x64.dmg" target="_blank" rel="noreferrer">下载 dmg</a></li><li>镜像加速：在上述直链前加前缀 <code>https://gh.xxooo.cf/</code></li><li>当前参考版本：<code>v2.4.7</code></li></ul><p>架构选择：Apple Silicon（M 系列）选 <code>aarch64</code> 包，Intel Mac 选 <code>x64</code> 包。</p><h2 id="macos-安全设置" tabindex="-1">macOS 安全设置 <a class="header-anchor" href="#macos-安全设置" aria-label="Permalink to &quot;macOS 安全设置&quot;">​</a></h2><p>首次运行可能提示「无法验证开发者」，按以下三步允许运行：</p><p><strong>1. 出现安全提示</strong>：首次打开时提示无法验证开发者，先点「好」关闭。</p><p><img src="'+o+'" alt="无法验证开发者提示"></p><p><strong>2. 在系统设置中允许</strong>：打开「系统设置 -&gt; 隐私与安全性」，在安全性区域找到被阻止的提示，点击<strong>仍要打开</strong>。</p><p><img src="'+l+'" alt="在隐私与安全性中点击仍要打开"></p><p><strong>3. 确认打开</strong>：在弹出的确认窗口点击<strong>打开</strong>，应用即可正常启动。</p><p><img src="'+n+'" alt="确认打开应用"></p><h2 id="配置教程" tabindex="-1">配置教程 <a class="header-anchor" href="#配置教程" aria-label="Permalink to &quot;配置教程&quot;">​</a></h2><h3 id="步骤一-复制订阅链接" tabindex="-1">步骤一：复制订阅链接 <a class="header-anchor" href="#步骤一-复制订阅链接" aria-label="Permalink to &quot;步骤一：复制订阅链接&quot;">​</a></h3><p>登录<a href="https://freedomport.cc/#/dashboard" target="_blank" rel="noreferrer">自由港机场会员中心</a>，在「我的订阅」的订阅链接区域，点击右侧的<strong>复制</strong>按钮复制订阅链接。</p><p><img src="'+i+'" alt="在会员中心复制订阅链接"></p><h3 id="步骤二-导入订阅" tabindex="-1">步骤二：导入订阅 <a class="header-anchor" href="#步骤二-导入订阅" aria-label="Permalink to &quot;步骤二：导入订阅&quot;">​</a></h3><p>打开 Clash Verge，点击左侧的<strong>订阅</strong>，将复制的链接粘贴到顶部的订阅文件链接框，点击<strong>导入</strong>。</p><p><img src="'+c+'" alt="在订阅页粘贴链接并导入"></p><h3 id="步骤三-更新订阅" tabindex="-1">步骤三：更新订阅 <a class="header-anchor" href="#步骤三-更新订阅" aria-label="Permalink to &quot;步骤三：更新订阅&quot;">​</a></h3><p>导入成功后会出现订阅卡片。如果之后遇到无法使用的情况，先点击右上角的<strong>刷新</strong>图标或订阅卡片上的刷新按钮，更新托管获取最新节点。</p><p><img src="'+h+'" alt="更新订阅托管"></p><h3 id="步骤四-开启系统代理" tabindex="-1">步骤四：开启系统代理 <a class="header-anchor" href="#步骤四-开启系统代理" aria-label="Permalink to &quot;步骤四：开启系统代理&quot;">​</a></h3><p>进入左侧的<strong>设置</strong>页，打开<strong>系统代理</strong>开关即可开始代理上网。其他选项如不了解，不要随意开启。</p><p><img src="'+g+'" alt="在设置页开启系统代理"></p><h3 id="步骤五-选择模式与节点" tabindex="-1">步骤五：选择模式与节点 <a class="header-anchor" href="#步骤五-选择模式与节点" aria-label="Permalink to &quot;步骤五：选择模式与节点&quot;">​</a></h3><p>进入左侧的<strong>代理</strong>页：</p><ul><li>使用默认的<strong>规则</strong>模式即可自动分流（国内直连、国外走代理）</li><li>点击展开 <strong>Proxy</strong> 策略组，手动指定要使用的节点</li><li>日常使用不建议选择 Auto-UrlTest，手动选一个延迟较低的节点更稳定</li></ul><p><img src="'+p+'" alt="在代理页选择模式与节点"></p><p>选择完成后，打开浏览器访问外网验证是否连接正常。</p><h2 id="主要功能" tabindex="-1">主要功能 <a class="header-anchor" href="#主要功能" aria-label="Permalink to &quot;主要功能&quot;">​</a></h2><ul><li><strong>流量监控</strong>：实时查看上行 / 下行速率与连接、规则命中情况</li><li><strong>策略组</strong>：支持自动选择、手动切换、负载均衡，网络波动时可快速切换</li><li><strong>跨设备一致</strong>：与 Windows 版配置习惯一致，便于多设备使用</li></ul><h2 id="常见问题" tabindex="-1">常见问题 <a class="header-anchor" href="#常见问题" aria-label="Permalink to &quot;常见问题&quot;">​</a></h2><p><strong>Q: 导入后节点为空？</strong> A: 先手动更新订阅（步骤三）；确认订阅链接可访问；确认套餐有效、流量未用完。</p><p><strong>Q: 已连接但不能访问？</strong> A: 检查系统代理开关是否已开；切换节点；确认本机时间正确。</p><p><strong>Q: 启动被系统拦截？</strong> A: 按上方「macOS 安全设置」在隐私与安全性中允许应用，再重新打开。</p><p>更多问题见<a href="./../../guide/faq">常见问题 FAQ</a>。</p><hr><blockquote><p>最后更新：2026 年 3 月 28 日 · 适用版本 Clash Verge Rev v2.4.7</p></blockquote>',43)])])}const C=a(d,[["render",m]]);export{x as __pageData,C as default};
